/* TOP 5 — Grafana | layout equilibrado, leve no CPU (sem blur pesado, sem animações infinitas) */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    --bg-void: #06080f;
    --bg-surface: rgba(15, 20, 34, 0.72);
    --bg-card: rgba(22, 28, 45, 0.85);
    --bg-elevated: rgba(32, 40, 62, 0.55);
    --glass-border: rgba(255, 255, 255, 0.08);
    --text-primary: #f8fafc;
    --text-secondary: #c4c9d4;
    --text-muted: #8b93a8;

    --gold: #e8c547;
    --gold-soft: #f5e6a8;
    --gold-deep: #a67c00;
    --gold-glow: rgba(232, 197, 71, 0.55);

    --silver: #d7dee8;
    --silver-mid: #9ca8b8;
    --silver-glow: rgba(199, 210, 224, 0.45);

    --bronze: #c67f48;
    --bronze-deep: #7d4d28;
    --bronze-glow: rgba(198, 127, 72, 0.42);

    --accent: #6ee7ff;
    --radius-lg: 1.25rem;
    --radius-md: 0.95rem;
    --font: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", sans-serif;
    --content-max: min(1260px, 96%);
    /* Aumente no CSS do painel se o cabeçalho ainda encostar no topo do Grafana */
    --grafana-panel-inset-top: clamp(3.25rem, 5.5vmin + 1.75rem, 6.25rem);
}

html, body {
    width: 100%;
    min-height: 100%;
}

body {
    font-family: var(--font);
    color: var(--text-primary);
    line-height: 1.45;
    overflow-x: hidden;
    overflow-y: auto;
    background-color: var(--bg-void);
    background-image:
        radial-gradient(ellipse 85% 55% at 50% -20%, rgba(79, 70, 229, 0.14), transparent 50%),
        radial-gradient(ellipse 50% 40% at 100% 0%, rgba(232, 197, 71, 0.06), transparent 45%),
        radial-gradient(ellipse 45% 50% at 0% 80%, rgba(56, 189, 248, 0.05), transparent 40%);
}

/* Luzes estáticas (sem animação, blur moderado) */
.deco-orbs {
    pointer-events: none;
    position: absolute;
    inset: 0;
    z-index: 0;
    overflow: hidden;
    min-height: 240px;
}

.orb {
    position: absolute;
    border-radius: 50%;
    filter: blur(48px);
    opacity: 0.28;
    will-change: auto;
}

.orb-a {
    width: min(50vw, 380px);
    height: min(50vw, 380px);
    top: 6%;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(99, 102, 241, 0.35);
}

.orb-b {
    width: 280px;
    height: 280px;
    bottom: 12%;
    right: -4%;
    background: rgba(232, 197, 71, 0.14);
}

.orb-c {
    width: 220px;
    height: 220px;
    bottom: 28%;
    left: -5%;
    background: rgba(56, 189, 248, 0.12);
}

.widescreen-layout {
    position: relative;
    z-index: 1;
    width: 100%;
    padding: max(1.1rem, var(--grafana-panel-inset-top)) clamp(0.6rem, 2.2vw, 1.35rem) clamp(1.85rem, 3.5vw, 2.65rem);
}

.main-content {
    position: relative;
    z-index: 2;
    width: var(--content-max);
    max-width: 100%;
    margin: 0 auto;
    display: flex;
    flex-direction: column;
    gap: clamp(1.35rem, 2.8vw, 1.85rem);
}

/* Cabeçalho */
.page-header {
    text-align: center;
    padding: clamp(1.15rem, 2.2vw, 1.45rem) clamp(1rem, 2.5vw, 1.6rem) clamp(1.2rem, 2.4vw, 1.55rem);
    margin-top: 0.25rem;
    border-radius: var(--radius-lg);
    background: rgba(18, 24, 40, 0.65);
    border: 1px solid rgba(255, 255, 255, 0.08);
    box-shadow: 0 12px 32px rgba(0, 0, 0, 0.18);
    animation: fadeEnter 0.5s ease backwards;
}

.page-kicker {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--gold-soft);
    margin-bottom: 0.6rem;
    padding: 0.38rem 1rem;
    border-radius: 999px;
    background: rgba(232, 197, 71, 0.1);
    border: 1px solid rgba(232, 197, 71, 0.28);
}

.page-kicker::before {
    content: "";
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: var(--gold);
}

.page-title {
    font-size: clamp(1.65rem, 3.4vw + 0.5rem, 2.4rem);
    font-weight: 800;
    letter-spacing: -0.03em;
    line-height: 1.15;
    color: #f8fafc;
}

.page-subtitle {
    font-size: clamp(0.86rem, 1.1vw + 0.4rem, 1rem);
    font-weight: 500;
    color: var(--text-muted);
    margin-top: 0.45rem;
    letter-spacing: 0.04em;
}

/* Pódio — palco */
.podium-section {
    flex-shrink: 0;
    animation: fadeEnter 0.55s ease 0.06s backwards;
}

.podium-wrap {
    position: relative;
    border-radius: var(--radius-lg);
    padding: 1px;
    overflow: hidden;
    background: linear-gradient(145deg, rgba(255, 255, 255, 0.12), rgba(99, 102, 241, 0.08));
    box-shadow: 0 10px 36px rgba(0, 0, 0, 0.28);
}

.podium-wrap::before {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    background: rgba(17, 23, 36, 0.92);
    z-index: 0;
}

.podium-aurora {
    position: absolute;
    inset: 0;
    background:
        radial-gradient(ellipse 70% 55% at 50% 100%, rgba(232, 197, 71, 0.07), transparent 55%),
        radial-gradient(ellipse 50% 45% at 15% 30%, rgba(99, 102, 241, 0.06), transparent 50%);
    z-index: 1;
    pointer-events: none;
    opacity: 1;
    animation: podiumAuroraBreathe 12s ease-in-out infinite alternate;
}

.podium-light-beam {
    display: block;
    position: absolute;
    top: 0;
    left: -35%;
    width: 40%;
    height: 100%;
    background: linear-gradient(
        95deg,
        transparent 0%,
        rgba(255, 252, 240, 0.05) 42%,
        rgba(255, 248, 220, 0.14) 50%,
        rgba(255, 252, 240, 0.05) 58%,
        transparent 100%
    );
    transform: skewX(-12deg);
    pointer-events: none;
    z-index: 3;
    animation: podiumShineSweep 11s ease-in-out infinite;
    opacity: 0;
}

.podium-container {
    position: relative;
    z-index: 4;
    display: flex;
    flex-direction: row;
    align-items: flex-end;
    justify-content: center;
    gap: clamp(0.95rem, 2.2vw, 1.65rem);
    padding: clamp(1.35rem, 2.4vw, 2.05rem) clamp(0.55rem, 1.4vw, 1.05rem) clamp(1.55rem, 2.6vw, 2.15rem);
}

@keyframes fadeEnter {
    from { opacity: 0; }
    to { opacity: 1; }
}

@keyframes podiumAuroraBreathe {
    from { opacity: 0.92; }
    to { opacity: 1; }
}

/* Reflexo que atravessa o palco (só opacidade + translate — leve) */
@keyframes podiumShineSweep {
    0%, 72%, 100% {
        transform: skewX(-12deg) translateX(0);
        opacity: 0;
    }
    76% { opacity: 0.6; }
    84% {
        transform: skewX(-12deg) translateX(420%);
        opacity: 0.4;
    }
    90% { opacity: 0; }
}

/* Entrada: laterais sobem juntas; campeão sobe mais alto */
@keyframes podiumRevealSide {
    from {
        opacity: 0;
        transform: translateY(1.65rem) scale(0.96);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

@keyframes podiumRevealChamp {
    from {
        opacity: 0;
        transform: translateY(2.25rem) scale(0.94);
    }
    to {
        opacity: 1;
        transform: translateY(-14px) scale(1);
    }
}

@keyframes podiumRevealChampFlat {
    from {
        opacity: 0;
        transform: translateY(1.5rem) scale(0.96);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

/* Halo dourado bem suave no 1º (loop longo) */
@keyframes podiumChampGlow {
    0%, 100% {
        box-shadow:
            0 12px 34px rgba(0, 0, 0, 0.32),
            0 0 0 1px rgba(232, 197, 71, 0.2),
            0 0 20px rgba(232, 197, 71, 0.12);
    }
    50% {
        box-shadow:
            0 12px 34px rgba(0, 0, 0, 0.32),
            0 0 0 1px rgba(232, 197, 71, 0.38),
            0 0 40px rgba(232, 197, 71, 0.22);
    }
}

/* Cartão pódio */
.podium-item {
    position: relative;
    flex: 1 1 0;
    min-width: 0;
    max-width: min(348px, 33.5%);
    padding: clamp(1.15rem, 2vw, 1.55rem) clamp(0.9rem, 1.65vw, 1.25rem) clamp(1.2rem, 2.1vw, 1.55rem);
    border-radius: clamp(var(--radius-md), 1.2vw, 1.15rem);
    text-align: center;
    overflow: visible;
    isolation: isolate;
    background: var(--bg-card);
    border: 1px solid var(--glass-border);
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.22);
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.podium-item:hover {
    transform: translateY(-4px);
    box-shadow: 0 12px 28px rgba(0, 0, 0, 0.28);
}

.podium-bar {
    position: absolute;
    top: 0;
    left: 0.6rem;
    right: 0.6rem;
    height: 4px;
    border-radius: 999px;
    z-index: 2;
}

.podium-bar-first {
    left: 0.45rem;
    right: 0.45rem;
    height: 5px;
    background: linear-gradient(90deg, var(--gold-deep), var(--gold), #fff5c4, var(--gold-soft));
    box-shadow: 0 0 12px rgba(232, 197, 71, 0.35);
}

.podium-bar-second {
    height: 4px;
    background: linear-gradient(90deg, #6b7a8f, var(--silver-mid), #f4f7fb, var(--silver));
    box-shadow: 0 0 10px rgba(199, 210, 224, 0.28);
}

.podium-bar-third {
    height: 4px;
    background: linear-gradient(90deg, #5c3d24, var(--bronze-deep), var(--bronze), #f0b27a);
    box-shadow: 0 0 10px rgba(198, 127, 72, 0.3);
}

/* Foto — anel duplo */
.podium-photo-wrap {
    position: relative;
    margin: 0.85rem auto 0.55rem;
    border-radius: 50%;
    z-index: 3;
}

.podium-photo {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    border-radius: 50%;
}

.podium-photo-third {
    width: clamp(104px, 11.5vw, 132px);
    height: clamp(104px, 11.5vw, 132px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.35), 0 0 0 3px rgba(198, 127, 72, 0.55);
}

.podium-photo-second {
    width: clamp(112px, 12.5vw, 142px);
    height: clamp(112px, 12.5vw, 142px);
    box-shadow: 0 6px 22px rgba(0, 0, 0, 0.35), 0 0 0 3px rgba(180, 195, 212, 0.6);
}

.podium-photo-first {
    width: clamp(126px, 14vw, 162px);
    height: clamp(126px, 14vw, 162px);
    box-shadow: 0 8px 26px rgba(0, 0, 0, 0.38), 0 0 0 3px rgba(232, 197, 71, 0.6);
}

.podium-crown {
    position: absolute;
    top: 0.4rem;
    right: 0.5rem;
    font-size: clamp(1.2rem, 2vw, 1.45rem);
    z-index: 5;
    filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.4));
}

.podium-label {
    position: relative;
    z-index: 2;
    font-size: clamp(0.62rem, 0.85vw, 0.74rem);
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.2em;
    color: var(--text-muted);
    margin-bottom: 0.45rem;
    line-height: 1.35;
}

/* Prata (2º) — rótulo explícito */
.podium-second .podium-label {
    color: #c8d4e4;
    text-shadow: 0 1px 0 rgba(0, 0, 0, 0.35);
}

/* Bronze (3º) — rótulo explícito */
.podium-third .podium-label {
    color: #eab08a;
    text-shadow: 0 1px 0 rgba(0, 0, 0, 0.4);
}

.podium-label-first {
    color: #fff2b8;
    letter-spacing: 0.2em;
    text-shadow: 0 0 12px rgba(232, 197, 71, 0.35);
}

.podium-name {
    position: relative;
    z-index: 2;
    font-size: clamp(0.94rem, 1.45vw + 0.38rem, 1.14rem);
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.45rem;
    line-height: 1.28;
    min-height: 2.7rem;
    display: flex;
    align-items: center;
    justify-content: center;
}

.podium-name-first {
    font-size: clamp(1.02rem, 1.7vw + 0.38rem, 1.22rem);
    min-height: 3rem;
    font-weight: 800;
}

.podium-second .podium-score {
    color: #eef2f8;
}

.podium-third .podium-score {
    color: #fde8d8;
}

.podium-score {
    position: relative;
    z-index: 2;
    font-size: clamp(1.58rem, 2.75vw + 0.4rem, 2.1rem);
    font-weight: 800;
    font-variant-numeric: tabular-nums;
    color: var(--text-primary);
    margin-bottom: 0.75rem;
    letter-spacing: -0.02em;
}

/* Pontuação 1º: SEM background-clip (Grafana some o texto com color:transparent) */
.podium-score-first {
    font-size: clamp(1.95rem, 3.4vw + 0.45rem, 2.55rem);
    font-weight: 800;
    color: #fff4c2;
    text-shadow: 0 2px 14px rgba(232, 197, 71, 0.45);
}

.podium-score-first .pts {
    color: #e8d9a8;
    text-shadow: none;
    font-weight: 700;
}

.pts {
    font-size: clamp(0.74rem, 1.05vw, 0.85rem);
    font-weight: 600;
    color: var(--text-muted);
    margin-left: 0.08em;
}

/* Stats em chips */
.podium-details {
    position: relative;
    z-index: 2;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 0.5rem;
    padding-top: 0.85rem;
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    text-align: center;
}

.podium-details-first {
    border-top-color: rgba(232, 197, 71, 0.32);
}

.podium-second .podium-details {
    border-top-color: rgba(199, 210, 224, 0.2);
}

.podium-third .podium-details {
    border-top-color: rgba(198, 127, 72, 0.25);
}

.detail-item {
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    padding: 0.45rem 0.35rem;
    border-radius: 0.55rem;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.05);
}

.detail-item.detail-full {
    grid-column: 1 / -1;
}

.detail-value {
    font-size: clamp(0.95rem, 1.35vw + 0.38rem, 1.15rem);
    font-weight: 700;
    font-variant-numeric: tabular-nums;
    color: var(--text-primary);
}

.detail-label {
    font-size: clamp(0.56rem, 0.75vw, 0.66rem);
    font-weight: 600;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

/* Metais — ordem flex: 3 | 1 | 2 (bordas e fundo mais legíveis) */
.podium-third {
    order: 1;
    animation: podiumRevealSide 0.72s cubic-bezier(0.22, 1, 0.36, 1) 0.08s both;
    border: 2px solid rgba(198, 127, 72, 0.55);
    background: linear-gradient(
        168deg,
        rgba(198, 127, 72, 0.24) 0%,
        rgba(90, 55, 32, 0.12) 22%,
        rgba(22, 28, 45, 0.94) 52%
    );
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.22), inset 0 1px 0 rgba(240, 178, 122, 0.12);
}

.podium-third:hover {
    box-shadow: 0 14px 32px rgba(0, 0, 0, 0.28), 0 0 0 1px rgba(198, 127, 72, 0.2);
}

.podium-second {
    order: 3;
    animation: podiumRevealSide 0.72s cubic-bezier(0.22, 1, 0.36, 1) 0.18s both;
    border: 2px solid rgba(168, 184, 204, 0.45);
    background: linear-gradient(
        168deg,
        rgba(199, 210, 224, 0.2) 0%,
        rgba(90, 102, 118, 0.1) 22%,
        rgba(22, 28, 45, 0.94) 52%
    );
    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.22), inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

.podium-second:hover {
    box-shadow: 0 14px 32px rgba(0, 0, 0, 0.28), 0 0 0 1px rgba(168, 184, 204, 0.25);
}

.podium-first {
    order: 2;
    flex: 1.08 1 0;
    max-width: min(388px, 37%);
    z-index: 6;
    border: 2px solid rgba(232, 197, 71, 0.65);
    background: linear-gradient(
        172deg,
        rgba(232, 197, 71, 0.28) 0%,
        rgba(140, 112, 28, 0.12) 22%,
        rgba(22, 28, 45, 0.92) 45%,
        rgba(12, 16, 28, 0.98) 100%
    );
    animation:
        podiumRevealChamp 0.88s cubic-bezier(0.22, 1, 0.36, 1) 0.28s both,
        podiumChampGlow 5.5s ease-in-out 1.15s infinite;
}

.podium-first:hover {
    transform: translateY(-18px) scale(1.01);
}

/* 4º e 5º */
.honors-section {
    animation: fadeEnter 0.5s ease 0.1s backwards;
}

.section-heading {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    margin-bottom: 0.35rem;
}

.section-heading-line {
    flex: 1;
    max-width: 140px;
    height: 2px;
    border-radius: 2px;
    background: linear-gradient(90deg, transparent, rgba(167, 139, 250, 0.35), rgba(110, 231, 255, 0.3), transparent);
}

.honors-title {
    font-size: 0.8rem;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.28em;
    color: #e2e8f0;
    white-space: nowrap;
}

.honors-desc {
    text-align: center;
    font-size: 0.82rem;
    color: #9ca8bc;
    margin-bottom: 1.1rem;
    font-weight: 500;
}

.honors-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: clamp(1rem, 2.2vw, 1.35rem);
}

.honor-card {
    position: relative;
    border-radius: 1.05rem;
    padding: clamp(1.2rem, 2vw, 1.45rem) clamp(1.15rem, 2.2vw, 1.55rem);
    min-height: clamp(120px, 14vh, 138px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.95rem;
    background: rgba(22, 28, 45, 0.92);
    border: 1px solid rgba(110, 231, 255, 0.2);
    box-shadow: 0 10px 28px rgba(0, 0, 0, 0.24);
    transition: transform 0.2s ease, border-color 0.2s ease, box-shadow 0.2s ease;
}

.honor-card:hover {
    transform: translateY(-3px);
    border-color: rgba(110, 231, 255, 0.35);
    box-shadow: 0 14px 32px rgba(0, 0, 0, 0.28);
}

.honor-content {
    display: flex;
    align-items: center;
    gap: 1.1rem;
    flex: 1;
    min-width: 0;
}

.honor-rank {
    flex-shrink: 0;
    width: clamp(3rem, 5vw, 3.5rem);
    height: clamp(3rem, 5vw, 3.5rem);
    border-radius: 0.9rem;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1rem;
    font-weight: 800;
    font-variant-numeric: tabular-nums;
    color: #c4f5ff;
    background: linear-gradient(155deg, rgba(110, 231, 255, 0.22), rgba(25, 35, 55, 0.95));
    border: 1px solid rgba(110, 231, 255, 0.4);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.1);
}

.honor-name {
    font-size: clamp(0.92rem, 1.35vw + 0.3rem, 1.06rem);
    font-weight: 700;
    color: var(--text-primary);
    line-height: 1.28;
    margin-bottom: 0.28rem;
}

.honor-stats {
    font-size: clamp(0.78rem, 1.1vw + 0.25rem, 0.9rem);
    color: #8f9bb3;
    font-weight: 500;
}

/* Badge de pontos — sempre visível no Grafana */
.honor-score {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    min-width: clamp(6rem, 11vw, 7.5rem);
    padding: clamp(0.9rem, 1.5vw, 1.15rem) clamp(1rem, 1.8vw, 1.25rem);
    border-radius: 0.95rem;
    text-align: center;
    background: rgba(12, 18, 32, 0.95);
    border: 1px solid rgba(110, 231, 255, 0.35);
    box-shadow: 0 6px 18px rgba(0, 0, 0, 0.22);
}

.score-value {
    font-size: clamp(1.75rem, 2.8vw + 0.35rem, 2.2rem);
    font-weight: 800;
    font-variant-numeric: tabular-nums;
    line-height: 1;
    color: #d4f8ff;
}

.score-label {
    display: block;
    font-size: 0.62rem;
    text-transform: uppercase;
    font-weight: 800;
    color: #8ab4c4;
    margin-top: 0.35rem;
    letter-spacing: 0.14em;
}

.footer {
    text-align: center;
    padding: 0.5rem 0 0.25rem;
}

.footer-text {
    font-size: 0.68rem;
    font-weight: 500;
    color: var(--text-muted);
    opacity: 0.85;
}

/* Responsivo */
@media (max-width: 720px) {
    .podium-container {
        flex-wrap: wrap;
        justify-content: center;
    }

    .podium-first {
        order: -1;
        width: 100%;
        max-width: min(480px, 94%);
        flex: 1 1 100%;
        animation:
            podiumRevealChampFlat 0.88s cubic-bezier(0.22, 1, 0.36, 1) 0.28s both,
            podiumChampGlow 5.5s ease-in-out 1.15s infinite;
    }

    .podium-first:hover {
        transform: translateY(-6px) scale(1.01);
    }

    .podium-second,
    .podium-third {
        max-width: 47%;
    }

    .honors-grid {
        grid-template-columns: 1fr;
    }

    .honor-card {
        flex-direction: row;
        flex-wrap: wrap;
        justify-content: center;
        text-align: center;
        min-height: 0;
        padding: 1.25rem 1.2rem;
    }

    .honor-content {
        flex: 1 1 100%;
        justify-content: center;
    }

    .honor-score {
        min-width: 100%;
        flex-direction: row;
        gap: 0.85rem;
        padding: 0.85rem 1rem;
    }

    .section-heading-line {
        max-width: 48px;
    }
}

@media (max-width: 480px) {
    .podium-second,
    .podium-third {
        max-width: 100%;
    }

    .page-kicker {
        letter-spacing: 0.14em;
        font-size: 0.62rem;
    }
}

/* Reduz movimento para quem prefere */
@media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
    }
}

options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}
